**State:**
```ts
const [tasks, setTasks] = useState<RevisionTask[]>([]);
const [sortMode, setSortMode] = useState<'severity' | 'story_order' | 'quick_wins'>('severity');
const [filterIssueType, setFilterIssueType] = useState<IssueType | 'all'>('all');
const [filterSeverity, setFilterSeverity] = useState<Severity | 'all'>('all');
const [filterStatus, setFilterStatus] = useState<'open' | 'snoozed' | 'done' | 'all'>('open');
const [formOpen, setFormOpen] = useState(false);
const [editingTask, setEditingTask] = useState<RevisionTask | null>(null);
```

**Data loading:**
```ts
const loadTasks = useCallback(() => {
  setTasks(getRevisionTasks(storyId));
}, [storyId]);

useEffect(() => { loadTasks(); }, [loadTasks]);
```

**`resolveEffectiveStatus` helper (pure function, defined outside component):**
```ts
function resolveEffectiveStatus(task: RevisionTask): TaskStatus {
  if (
    task.status === 'snoozed' &&
    task.snoozedUntil !== null &&
    task.snoozedUntil <= Date.now()
  ) {
    return 'open';
  }
  return task.status;
}
```

**Sort functions:**

`sortBySeverity`: order map `{ critical: 0, major: 1, minor: 2, polish: 3 }`, sort ascending. Snoozed tasks (effective status `'snoozed'`) always sort after open tasks regardless of severity.

`sortByStoryOrder`: match `task.sceneId` to `scenes.find(s => s.id === task.sceneId)?.order ?? Infinity`. `null` sceneId maps to `Infinity` (goes last). Sort ascending by `order`.

`sortByQuickWins`: reverse severity order — `{ polish: 0, minor: 1, major: 2, critical: 3 }`. Snoozed tasks still go last.

**Filtered + sorted task list:**

```ts
const displayTasks = useMemo(() => {
  let result = tasks.map(t => ({ ...t, effectiveStatus: resolveEffectiveStatus(t) }));

  // Apply filters
  if (filterStatus !== 'all') {
    result = result.filter(t => t.effectiveStatus === filterStatus);
  }
  if (filterIssueType !== 'all') {
    result = result.filter(t => t.issueType === filterIssueType);
  }
  if (filterSeverity !== 'all') {
    result = result.filter(t => t.severity === filterSeverity);
  }

  // Sort
  result = result.sort(/* chosen sort fn */);
  return result;
}, [tasks, sortMode, filterIssueType, filterSeverity, filterStatus, scenes]);
```

**Empty state logic:**
- `tasks.length === 0`: "No revision tasks yet." + "Add your first task" CTA button → opens form
- `tasks.length > 0 && displayTasks.length === 0`: "No tasks match this filter." + "Clear filters" button → resets all filters to `'all'`

**Layout JSX structure:**
```tsx
