### Step 10 — Wire up handlers in `RevisionQueue`

```ts
const handleCreate = (fields: Omit<RevisionTask, 'id' | 'storyId' | 'createdAt' | 'updatedAt'>) => {
  addRevisionTask(storyId, fields);
  loadTasks();
  setFormOpen(false);
};

const handleUpdate = (updated: RevisionTask) => {
  updateRevisionTask(storyId, updated.id, {
    title: updated.title,
    issueType: updated.issueType,
    severity: updated.severity,
    sceneId: updated.sceneId,
    source: updated.source,
    sourceRef: updated.sourceRef,
    status: updated.status,
    snoozedUntil: updated.snoozedUntil,
  });
  loadTasks();
  setEditingTask(null);
};

const handleComplete = (id: string) => {
  completeRevisionTask(storyId, id);
  loadTasks();
};

const handleSnooze = (id: string) => {
  snoozeRevisionTask(storyId, id, Date.now() + 7 * 24 * 60 * 60 * 1000);
  loadTasks();
};

const handleDelete = (id: string) => {
  deleteRevisionTask(storyId, id);
  loadTasks();
};
```

