  whatIsNext: string;           // "" when skipped
  createdAt: string;            // ISO 8601
}

export interface SessionState {
  storyId: string;
  lastEditedSceneId: string | null;
  lastEditedSceneTitle: string | null;
  lastEditorScrollTop: number;
  lastEditorCursorOffset: number;
  lastHandoffNoteId: string | null;
  updatedAt: string;            // ISO 8601
}
