### Step 3: Create `src/lib/timeline.ts`

```ts
import type { Scene } from '@/types/scene';

export interface TimelineConflict {
  sceneIds: [string, string];
  duplicateDate: string;
  storylineTag: string;
}

export function detectConflicts(scenes: Scene[]): TimelineConflict[] {
  const conflicts: TimelineConflict[] = [];
  const byTag = new Map<string, Scene[]>();
  for (const scene of scenes) {
    const tag = (scene.storylineTag ?? '').trim();
    const date = (scene.timelineDate ?? '').trim();
    if (!tag || !date) continue;
    if (!byTag.has(tag)) byTag.set(tag, []);
    byTag.get(tag)!.push(scene);
  }
  for (const [tag, tagScenes] of byTag) {
    const dateMap = new Map<string, Scene[]>();
    for (const s of tagScenes) {
      const d = s.timelineDate!.trim();
      if (!dateMap.has(d)) dateMap.set(d, []);
      dateMap.get(d)!.push(s);
    }
    for (const [date, group] of dateMap) {
      for (let i = 0; i < group.length - 1; i++) {
        for (let j = i + 1; j < group.length; j++) {
          conflicts.push({ sceneIds: [group[i].id, group[j].id], duplicateDate: date, storylineTag: tag });
        }
      }
    }
  }
  return conflicts;
}

export function sortForTimeline(scenes: Scene[]): Scene[] {
  const withDate = scenes.filter((s) => (s.timelineDate ?? '').trim() !== '');
  const withoutDate = scenes.filter((s) => (s.timelineDate ?? '').trim() === '');
  withDate.sort((a, b) => a.timelineDate!.localeCompare(b.timelineDate!));
  withoutDate.sort((a, b) => a.order - b.order);
  return [...withDate, ...withoutDate];
}
```

