interface TimelineRowProps {
  scene: Scene;
  chronologicalIndex: number;
  hasConflict: boolean;
  hasNoDate: boolean;
  onStatusChange: (sceneId: string, status: SceneStatus) => void;
  onTimelineFieldChange: (sceneId: string, field: 'timelineDate' | 'storylineTag', value: string) => void;
  onOpenScene: (sceneId: string) => void;
}

export function TimelineRow({ scene, chronologicalIndex, hasConflict, hasNoDate, onStatusChange, onTimelineFieldChange, onOpenScene }: TimelineRowProps) {
  const [editingField, setEditingField] = useState<'timelineDate' | 'storylineTag' | null>(null);
  const [dateDraft, setDateDraft] = useState(scene.timelineDate ?? '');
  const [tagDraft, setTagDraft] = useState(scene.storylineTag ?? '');

  useEffect(() => { setDateDraft(scene.timelineDate ?? ''); }, [scene.timelineDate]);
  useEffect(() => { setTagDraft(scene.storylineTag ?? ''); }, [scene.storylineTag]);

  const commitDate = () => { onTimelineFieldChange(scene.id, 'timelineDate', dateDraft.trim()); setEditingField(null); };
  const commitTag = () => { onTimelineFieldChange(scene.id, 'storylineTag', tagDraft.trim()); setEditingField(null); };

  const markerLabel = (scene.timelineDate ?? '').trim() ? scene.timelineDate!.trim() : `#${chronologicalIndex}`;

  return (
    <div className={`${styles.row} ${hasConflict ? styles.rowConflict : ''} ${hasNoDate ? styles.rowNoDate : ''}`} role="listitem">
      <div className={styles.markerCol}>
        {editingField === 'timelineDate' ? (
          <input autoFocus className={styles.markerInput} value={dateDraft} placeholder="e.g. 2045-06-12 or Day 3"
            aria-label="Timeline date or label" onChange={e => setDateDraft(e.target.value)} onBlur={commitDate}
            onKeyDown={e => { if (e.key === 'Enter') commitDate(); if (e.key === 'Escape') { setDateDraft(scene.timelineDate ?? ''); setEditingField(null); } }} />
        ) : (
          <button type="button" className={`${styles.marker} ${hasNoDate ? styles.markerEmpty : ''}`}
            onClick={() => setEditingField('timelineDate')}
            aria-label={scene.timelineDate ? `Timeline marker: ${scene.timelineDate}. Click to edit` : 'No timeline date. Click to add'}>
            {markerLabel}
          </button>
        )}
      </div>
      <div className={styles.identityCol}>
        <span className={styles.sceneTitle}>{scene.title}</span>
        <span className={styles.sceneChapter}>{scene.chapter}</span>
      </div>
      <div className={styles.tagCol}>
        {editingField === 'storylineTag' ? (
          <input autoFocus className={styles.tagInput} value={tagDraft} placeholder="e.g. Main, Subplot A"
            aria-label="Storyline tag" onChange={e => setTagDraft(e.target.value)} onBlur={commitTag}
            onKeyDown={e => { if (e.key === 'Enter') commitTag(); if (e.key === 'Escape') { setTagDraft(scene.storylineTag ?? ''); setEditingField(null); } }} />
        ) : (
          <button type="button" className={`${styles.tagChip} ${!scene.storylineTag ? styles.tagChipEmpty : ''}`}
            onClick={() => setEditingField('storylineTag')}
            aria-label={scene.storylineTag ? `Storyline: ${scene.storylineTag}. Click to edit` : 'No storyline tag. Click to add'}>
            {scene.storylineTag || 'Storyline'}
          </button>
        )}
      </div>
      <div className={styles.statusCol}>
        <select value={scene.status} onChange={e => onStatusChange(scene.id, e.target.value as SceneStatus)}
          className={styles.statusSelect} aria-label={`Status for ${scene.title}`}>
          <option value="planned">Planned</option>
          <option value="drafting">Drafting</option>
          <option value="done">Done</option>
        </select>
      </div>
      <div className={styles.flagCol}>
        {hasConflict && <span className={styles.conflictBadge} role="img" aria-label="Time conflict detected">Conflict</span>}
        {!hasConflict && hasNoDate && <span className={styles.noDateBadge} role="img" aria-label="No timeline data">No date</span>}
      </div>
      <div className={styles.ctaCol}>
        <button type="button" className={styles.openBtn} onClick={() => onOpenScene(scene.id)} aria-label={`Open scene: ${scene.title}`}>Open</button>
      </div>
    </div>
  );
}
