### Step 7: Create `src/components/Timeline/Timeline.tsx`

```tsx
'use client';
import { useState, useEffect, useMemo } from 'react';
import type { Scene, SceneStatus } from '@/types/scene';
import { sortForTimeline, detectConflicts } from '@/lib/timeline';
import { TimelineSummaryStrip, type TimelineFilter } from './TimelineSummaryStrip';
import { TimelineRow } from './TimelineRow';
import styles from './Timeline.module.css';
import rowStyles from './TimelineRow.module.css';

interface TimelineProps {
  storyId: string;
  scenes: Scene[];
  loading?: boolean;
  onStatusChange: (sceneId: string, status: SceneStatus) => void;
  onTimelineFieldChange: (sceneId: string, field: 'timelineDate' | 'storylineTag', value: string) => void;
  onOpenScene: (sceneId: string) => void;
}

export function Timeline({ scenes, loading = false, onStatusChange, onTimelineFieldChange, onOpenScene }: TimelineProps) {
  const [localScenes, setLocalScenes] = useState<Scene[]>(scenes);
  const [filter, setFilter] = useState<TimelineFilter>('all');

  useEffect(() => { setLocalScenes(scenes); }, [scenes]);

  const sortedScenes = useMemo(() => sortForTimeline(localScenes), [localScenes]);
  const conflicts = useMemo(() => detectConflicts(localScenes), [localScenes]);
  const conflictSceneIds = useMemo(() => {
    const ids = new Set<string>();
    conflicts.forEach(c => { ids.add(c.sceneIds[0]); ids.add(c.sceneIds[1]); });
    return ids;
  }, [conflicts]);
  const noDateSceneIds = useMemo(() => new Set(localScenes.filter(s => !(s.timelineDate ?? '').trim()).map(s => s.id)), [localScenes]);

  const displayScenes = filter === 'conflicts' ? sortedScenes.filter(s => conflictSceneIds.has(s.id)) : sortedScenes;

  if (loading) return <div className={styles.container}><div className={styles.loadingStrip}>Loading timeline…</div></div>;

  if (localScenes.length === 0) return (
    <div className={styles.container}>
      <div className={styles.emptyState}>
        <p className={styles.emptyTitle}>No scenes yet</p>
        <p className={styles.emptyBody}>Add scenes in the Corkboard view, then return here to set timeline dates.</p>
      </div>
    </div>
  );

  return (
    <div className={styles.container}>
      <TimelineSummaryStrip sceneCount={localScenes.length} conflictCount={conflicts.length}
        noDateCount={noDateSceneIds.size} filter={filter} onFilterChange={setFilter} />
      <div className={styles.list} role="list" aria-label="Timeline of scenes">
        <div className={rowStyles.headerRow} role="row" aria-hidden="true">
          {['When', 'Scene', 'Storyline', 'Status', 'Flags', ''].map((h, i) => (
            <span key={i} className={rowStyles.headerCell}>{h}</span>
          ))}
        </div>
        {displayScenes.map((scene, index) => (
          <TimelineRow key={scene.id} scene={scene} chronologicalIndex={index + 1}
            hasConflict={conflictSceneIds.has(scene.id)} hasNoDate={noDateSceneIds.has(scene.id)}
            onStatusChange={onStatusChange} onTimelineFieldChange={onTimelineFieldChange} onOpenScene={onOpenScene} />
        ))}
        {displayScenes.length === 0 && filter === 'conflicts' && (
          <div className={styles.emptyFilter}>No conflicts to show.</div>
        )}
      </div>
    </div>
  );
}
```

